 24→class Settings {
 25→    /**
 26→     * Version number of global and account settings.
 27→     *
 28→     * <p>
 29→     * This value is used as "version" attribute in the export file. It needs to be incremented
 30→     * when a global or account setting is added or removed, or when the format of a setting
 31→     * is changed (e.g. add a value to an enum).
 32→     * </p>
 33→     *
 34→     * @see SettingsExporter
 35→     */
 36→    public static final int VERSION = 100;
 37→
 38→    static Map<String, Object> validate(int version, Map<String, TreeMap<Integer, SettingsDescription<?>>> settings,
 39→            Map<String, String> importedSettings, boolean useDefaultValues) {
 40→
 41→        Map<String, Object> validatedSettings = new HashMap<>();
 42→        for (Map.Entry<String, TreeMap<Integer, SettingsDescription<?>>> versionedSetting : settings.entrySet()) {
 43→
 44→            // Get the setting description with the highest version lower than or equal to the
 45→            // supplied content version.
 46→            TreeMap<Integer, SettingsDescription<?>> versions = versionedSetting.getValue();
 47→            SortedMap<Integer, SettingsDescription<?>> headMap = versions.headMap(version + 1);
 48→
 49→            // Skip this setting if it was introduced after 'version'
 50→            if (headMap.isEmpty()) {
 51→                continue;
 52→            }
 53→
 54→            Integer settingVersion = headMap.lastKey();
 55→            SettingsDescription<?> desc = versions.get(settingVersion);
 56→
 57→            // Skip this setting if it is no longer used in 'version'
 58→            if (desc == null) {
 59→                continue;
 60→            }
 61→
 62→            String key = versionedSetting.getKey();
 63→
 64→            boolean useDefaultValue;
 65→            if (!importedSettings.containsKey(key)) {
 66→                Timber.v("Key \"%s\" wasn't found in the imported file.%s",
 67→                        key,
 68→                        (useDefaultValues) ? " Using default value." : "");
 69→
 70→                useDefaultValue = useDefaultValues;
 71→            } else {
 72→                String prettyValue = importedSettings.get(key);
 73→                try {
 74→                    Object internalValue = desc.fromPrettyString(prettyValue);
 75→                    validatedSettings.put(key, internalValue);
 76→                    useDefaultValue = false;
 77→                } catch (InvalidSettingValueException e) {
 78→                    Timber.v("Key \"%s\" has invalid value \"%s\" in imported file. %s",
 79→                            key,
 80→                            prettyValue,
 81→                            (useDefaultValues) ? "Using default value." : "Skipping.");
 82→
 83→                    useDefaultValue = useDefaultValues;
 84→                }
 85→            }
 86→
 87→            if (useDefaultValue) {
 88→                Object defaultValue = desc.getDefaultValue();
 89→                validatedSettings.put(key, defaultValue);
 90→            }
 91→        }
 92→
 93→        return validatedSettings;
 94→    }
